mapper.select:
SELECT r.id, r.inviter_user_id, r.invitee_user_id, r.invite_code, r.register_channel,
       r.register_ip, r.status, r.total_rebate, r.remark, r.create_time,
       iu.nick_name AS inviter_nick_name, iu.user_name AS inviter_user_name,
       eu.nick_name AS invitee_nick_name, eu.user_name AS invitee_user_name
FROM aid_invite_relation r
LEFT JOIN sys_user iu ON iu.user_id = r.inviter_user_id
LEFT JOIN sys_user eu ON eu.user_id = r.invitee_user_id

    r.del_flag = '0'
    AND r.inviter_user_id = #{inviterUserId}
    AND r.invitee_user_id = #{inviteeUserId}
    AND r.invite_code = #{inviteCode}
    AND r.status = #{status}
    AND r.register_channel = #{registerChannel}

ORDER BY r.id DESC
